<span class="line"><span style="color:#F8F8F2;">elements_input </span><span style="color:#F92672;">=</span><span style="color:#66D9EF;"> input</span><span style="color:#F8F8F2;">(</span><span style="color:#E6DB74;">&quot;Please enter a list of elements, separated by commas: &quot;</span><span style="color:#F8F8F2;">)</span></span>
